Span<nint> signedSpan = stackalloc nint[] { 1, 2, 3, -4, 5 };
Span<nuint> unsignedSpan = stackalloc nuint[] { 10, 20, 30, 40, 50 };

Console.WriteLine($"nint  size: {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

nint signedSum = 0;
foreach (var n in signedSpan)
    signedSum += n;

nuint unsignedSum = 0;
foreach (var n in unsignedSpan)
    unsignedSum += n;

Console.WriteLine($"Span<nint>  values: {string.Join(", ", signedSpan.ToArray())}  sum={signedSum}");
Console.WriteLine($"Span<nuint> values: {string.Join(", ", unsignedSpan.ToArray())}  sum={unsignedSum}");

